mapper.insert:

    SELECT  IFNULL(MAX(NTCN_NO),0)+1  AS NTCN_NO
      FROM  TB_NTFC_INFO

INSERT  INTO TB_NTFC_INFO
      ( NTCN_NO
      , NTCN_SJ
      , NTCN_CN
      , NTCN_TM
      , BH_NTCN_INTRVL
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{ntfcNo}
        , #{ntfcSj}
        , #{ntfcCn}
        , #{ntfcTime}
        , #{bhNtfcIntrvlString}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_NTFC_INFO
   SET  NTCN_SJ         = #{ntfcSj}
      , NTCN_CN         = #{ntfcCn}
      , NTCN_TM         = #{ntfcTime}
      , BH_NTCN_INTRVL  = #{bhNtfcIntrvlString}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  NTCN_NO = #{ntfcNo}
